-- 114（2025）主管會議匯入 — 加法式、只動 2025 年 mgmt_weekly，不碰 115 與使用者資料
begin;
delete from action_followups where meeting_id in (select id from meetings where meeting_type='mgmt_weekly' and meeting_date >= '2025-01-01' and meeting_date < '2026-01-01');
delete from meeting_action_items where source_meeting_id in (select id from meetings where meeting_type='mgmt_weekly' and meeting_date >= '2025-01-01' and meeting_date < '2026-01-01');
delete from meetings where meeting_type='mgmt_weekly' and meeting_date >= '2025-01-01' and meeting_date < '2026-01-01';
commit;